let runFast = false; // doubles map movement speed
// Enemy animation speed: 'slow' (2x), 'medium' (1x), 'fast' (0.5x).
// Multiplies every enemy-turn timer (showcase hold, arrow flight, gap
// between actions). Persisted with the rest of the options. Default is
// 'slow' — players who explicitly picked another setting in Options
// keep their pick (tracked via enemySpeedExplicit on the saved blob);
// players who never touched it (or are loading a save that predates
// this default change) get the new slow default.
let enemySpeed = 'slow';
let enemySpeedExplicit = false;
function getEnemySpeedMul() {
  if (enemySpeed === 'slow') return 2;
  if (enemySpeed === 'fast') return 0.5;
  return 1;
}

// === Options persistence ======================================
// Sound on/off + volume, music on/off + volume, run-fast.
// Loaded once at boot, saved whenever any option changes via the
// shared saveOptions() call below.
const OPTIONS_LS_KEY = 'cq_options_v1';
// True by default — show a confirm modal when the player clicks End
// Turn while at least one ally is still ready to attack. Toggled off
// from Options; persisted in localStorage alongside the other prefs.
let _endTurnWarnAllies = true;
// Modal flag — flipped on when the End Turn click finds unused
// allies; cleared by the Yes/No handler.
let _endTurnConfirmOpen = false;

function loadOptionsFromStorage() {
  try {
    const raw = localStorage.getItem(OPTIONS_LS_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw) || {};
    if (typeof parsed.runFast === 'boolean') runFast = parsed.runFast;
    if (typeof parsed.endTurnWarnAllies === 'boolean') _endTurnWarnAllies = parsed.endTurnWarnAllies;
    // Only honor the saved enemySpeed when the player explicitly
    // picked one in Options (enemySpeedExplicit flag). Older saves
    // and untouched-options saves fall through to the new 'fast'
    // default. Without this guard, every existing user — even ones
    // who never opened Options — would be locked into the old
    // 'medium' default that saveOptions() always wrote into the
    // serialized blob.
    if (parsed.enemySpeedExplicit === true &&
        (parsed.enemySpeed === 'slow' || parsed.enemySpeed === 'medium' || parsed.enemySpeed === 'fast')) {
      enemySpeed = parsed.enemySpeed;
      enemySpeedExplicit = true;
    }
    if (typeof parsed.soundEnabled === 'boolean' && parsed.soundEnabled !== isSoundEnabled()) {
      toggleSound();
    }
    if (typeof parsed.musicEnabled === 'boolean' && parsed.musicEnabled !== isMusicEnabled()) {
      toggleMusic();
    }
    if (typeof parsed.soundVolume === 'number') setSoundVolume(parsed.soundVolume);
    if (typeof parsed.musicVolume === 'number') setMusicVolume(parsed.musicVolume);
  } catch (e) { /* ignore — fall back to runtime defaults */ }
}
function saveOptions() {
  try {
    localStorage.setItem(OPTIONS_LS_KEY, JSON.stringify({
      runFast,
      enemySpeed,
      enemySpeedExplicit,
      soundEnabled: isSoundEnabled(),
      musicEnabled: isMusicEnabled(),
      soundVolume: getSoundVolume(),
      musicVolume: getMusicVolume(),
      endTurnWarnAllies: _endTurnWarnAllies,
    }));
  } catch (e) { /* private mode / quota — silently skip */ }
}

// === Tutorial system ==========================================
// Persisted in localStorage so the player keeps their tutorial
// state across page reloads. The per-id seen-set tracks which
// boxes have been dismissed so they don't pop a second time.
// Reset Tutorial (in Options) clears the seen-set so first-time
// hints fire again. Disabling the tutorial suppresses every box
// regardless of the seen-set; re-enabling re-evaluates.
// Bump this version any time the tutorial set gets a meaningful rewrite —
// loadTutorialState reads the new key, finds nothing, and every player
// starts fresh (existing v1 entry is orphaned harmlessly in localStorage).
// v2: added hover_preview / inventory_button / help_button / any_card_in_hand
// + the inventory rest tour. Wanted everyone to see the new boxes.
const TUTORIAL_LS_KEY = 'cq_tutorial_v2';
let _tutorialEnabled = true;
let _tutorialSeen = new Set();        // ids of boxes already dismissed
let _tutorialQueue = [];              // ids of boxes pending display
let _tutorialActiveId = null;         // currently-showing box, null when none
function loadTutorialState() {
  try {
    const raw = localStorage.getItem(TUTORIAL_LS_KEY);
    if (!raw) return;
    const parsed = JSON.parse(raw);
    _tutorialEnabled = parsed && parsed.enabled !== false;
    _tutorialSeen = new Set(Array.isArray(parsed && parsed.seen) ? parsed.seen : []);
  } catch (e) { /* ignore — corrupt storage falls back to defaults */ }
}
function saveTutorialState() {
  try {
    localStorage.setItem(TUTORIAL_LS_KEY, JSON.stringify({
      enabled: _tutorialEnabled,
      seen: Array.from(_tutorialSeen),
    }));
  } catch (e) { /* private mode / quota — silently skip */ }
}
function setTutorialEnabled(on) {
  _tutorialEnabled = !!on;
  if (!_tutorialEnabled) {
    _tutorialQueue = [];
    _tutorialActiveId = null;
  }
  saveTutorialState();
}
function resetTutorialProgress() {
  _tutorialSeen = new Set();
  _tutorialQueue = [];
  _tutorialActiveId = null;
  // Re-enable tutorials if they were off — the user clicked Reset
  // because they want to see the boxes again. Without flipping the
  // toggle, every showTutorial() call would still early-out.
  _tutorialEnabled = true;
  saveTutorialState();
}
// Registry of tutorial boxes. Each entry: { title, body, arrow? }.
// arrow is an optional function returning { x, y } in screen space
