let titleCardSubtitle = '';
let titleCardAlpha = 0;
let titleCardPhase = ''; // 'in', 'hold', 'out'
let titleCardTimer = 0;
let titleCardCallback = null;

// Damage number animations
let damageNumbers = []; // { x, y, text, color, timer, vy }

// Card badge hover hit areas (cleared each frame)
let cardBadgeHitAreas = []; // { x, y, w, h, label }

// Inline icon hit areas for keyword tooltips (cleared each frame)
let iconHitAreas = []; // { x, y, w, h, keyword }

// Combat intro state
let combatIntroTimer = 0;       // ms remaining
let combatIntroMessage = '';    // optional message under enemy art

// Character card splash (click on card to view full art)
let characterSplashCharacter = null; // null when no splash
let characterSplashIsPlayer = false;

// Hover preview state (cards/powers in combat)
let hoveredCardPreview = null; // a Card to render large
// Side-preview hand-off — when drawHoverPreview renders a sidecar
// (e.g. Harvest perk's Goodberry mini, Goodberries ability's Goodberry
// preview), it stashes the rect + the side card here. The next frame's
// hover gate (`maintainSideHoverExpansion`) checks the mouse against
// the stashed rect; if the mouse landed on it, we force hoveredCardPreview
// onto the side card so drawHoverPreview pops the side card at full size.
let _lastSidePreviewRect = null;
let _lastSidePreviewCard = null;
// Shift-to-freeze preview: while Shift is held, whichever preview is currently
// shown (card, power, or creature) stays pinned on screen so the player can
// mouse over its keyword icons (Scry, Heal, etc.) to read the tooltips without
// the preview changing — and a different card/power/creature hover cannot
// swap it out mid-inspection. Released Shift resumes normal hovering.
let shiftFreezeCard = null;
let shiftFreezePower = null;
let shiftFreezeCreature = null;
let shiftFreezeMouseX = 0;
let shiftFreezeMouseY = 0;
// Set by drawCreatureCard when the side-preview "i" badge is hovered.
// drawHoverPreview reads this on its second pass (after the main preview
// renders) so the tooltip lands on top of everything.
let _summonInfoHover = null;
function isShiftFrozen() {
  return !!(shiftFreezeCard || shiftFreezePower || shiftFreezeCreature);
}
let hoveredPowerPreview = null; // a Power to render large
let hoveredCreaturePreview = null; // a Creature to render large

// Hit areas for log entries that have a card attached (for hover preview)
let logCardHitAreas = []; // { x, y, w, h, card }

// === Combat Layout Constants ===
// Left section: 80% width (game area)
// Right section: 20% width (log + buttons)
const COMBAT_LEFT_W = Math.floor(SCREEN_WIDTH * 0.8);   // 1024
const COMBAT_RIGHT_X = COMBAT_LEFT_W;
const COMBAT_RIGHT_W = SCREEN_WIDTH - COMBAT_LEFT_W;    // 256

// Left side split horizontally (enemy on top, player on bottom)
const COMBAT_DIVIDER_Y = Math.floor(SCREEN_HEIGHT / 2); // 480
const COMBAT_ENEMY_AREA = { x: 0, y: 0, w: COMBAT_LEFT_W, h: COMBAT_DIVIDER_Y };
const COMBAT_PLAYER_AREA = { x: 0, y: COMBAT_DIVIDER_Y, w: COMBAT_LEFT_W, h: SCREEN_HEIGHT - COMBAT_DIVIDER_Y };

// Right side: log + button section.
const COMBAT_RIGHT_BTN_H = 160;
const COMBAT_RIGHT_LOG_H = SCREEN_HEIGHT - COMBAT_RIGHT_BTN_H; // 816
const COMBAT_RIGHT_BTN_Y = COMBAT_RIGHT_LOG_H;
const COMBAT_LOG_AREA = { x: COMBAT_RIGHT_X, y: 0, w: COMBAT_RIGHT_W, h: COMBAT_RIGHT_LOG_H };
const COMBAT_BTN_AREA = { x: COMBAT_RIGHT_X, y: COMBAT_RIGHT_BTN_Y, w: COMBAT_RIGHT_W, h: COMBAT_RIGHT_BTN_H };

// Special encounter state
let killCount = 0; // for kill-count encounters (wolf pack, etc.)
let killTarget = 0; // how many kills needed to win
let survivalRounds = 0; // total rounds (mirrors Python survival_rounds_total) — used as the bar denominator
let survivalRoundsRemaining = 0; // countdown — decremented at end of each enemy turn; victory at <= 0

// Swim mechanic (Piranha Pool fight). swimTarget=12 from PY: each
// player turn opens with a SWIMMING state where the player must
// recharge 1-3 hand cards. Each recharge counts as +1 swim.
// 12 swims = victory (escape the pool).
let swimTarget = 0;            // total swims needed to win (0 = no swim mechanic)
let swimCount = 0;             // swims completed so far
let swimCardsThisTurn = 0;     // swims this turn (cap 3, auto-finish at 3)
let swimFlashTimer = 0;        // ms of red flash for drowning (no cards)
let enemyTurnNumber = 0;
// Slyblade Sneak Attack scaler — counts enemy cards committed in the
// current enemy turn. Incremented just before each card's effect
// loop runs; reset in startEnemyTurn. PY's "cards_committed".
let _enemyCardsThisTurn = 0;
// Sentinel UX state — when the player tries to attack a non-sentinel while
// at least one living sentinel guards the row, briefly flash the sentinel
// creatures (gold pulse) and show a "Must target Sentinel" toast.
let sentinelFlashTimer = 0;

// Modal card state
let modalCard = null; // Card being played in modal mode
let modalTarget = null; // Target for modal card (enemy or creature)

// Scry state
let scryCards = []; // cards revealed for scry_pick
// scry_pick_discard sets this so unpicked cards return to the discard pile
// instead of the recharge pile (Kraken's Eye Spyglass).
let _scryFromDiscard = false;

// Power recharge state
let powerRechargeMode = false;
let powerRechargeCardsNeeded = 0;
let powerRechargeCardsSelected = [];
let selectedPower = null;

// Card recharge state (for cards with recharge_extra cost like Bow, Bone Club)
let cardRechargeMode = false;
// Flash of Genius perk — once at combat start, the player may
// recharge one card from their hand to draw 1 (per perk stack).
// flashOfGeniusMode gates clicks: Skip exits early, hand cards
// pay the recharge. Reset every startCombat so it never bleeds
// into the next fight.
let flashOfGeniusMode = false;
let flashOfGeniusRechargesLeft = 0;
// Deferred Flash of Genius picker — set when combat opens with an enemy
// surprise (ambush). The picker would otherwise overlay the enemy's
// free opening swing and hide the surprise damage, so we hold it back
// and open it on the player's first ACTUAL turn (in finishEnemyTurn).
let _flashOfGeniusPending = 0;
let _flashSkipRect = null;
let cardRechargeNeeded = 0;
let cardRechargedCards = []; // cards already paid as recharge cost
let pendingRechargeNames = []; // names to log after the card resolves

// Card discard-pick state (for cards with discard_extra cost like
// Harpy Talon Blade — player picks WHICH hand card to discard rather
// than the auto-random fallback used by enemy AI / NPC casters).
let cardDiscardPickMode = false;
let cardDiscardPickNeeded = 0;
let pendingDiscardNames = []; // names to log after the card resolves
// Full-undo snapshots taken when entering discard-pick mode. Cover
// hand, discardPile AND drawPile so a cancel cleanly reverses BOTH
// the discard cost (card goes back to hand) AND the on_discard rider
// fallout (cards drawn by Feather Cloak / Harpy Egg Omelette get
// pushed back onto the drawPile). Cleared once the play commits
// (enemy click, self-play, ally heal target) so a successful cast
// can't be rolled back.
let _discardPickHandSnapshot = null;
let _discardPickDiscardSnapshot = null;
let _discardPickDrawSnapshot = null;
// Snapshot of hand order taken when entering any recharge/barrage/power mode.
// Restored on cancel so the hand returns to exactly the same order.
let _handOrderSnapshot = null;

// Ally manual-attack state
let selectedAlly = null;

// Multi-target attack state (Wooden Axe etc.)
let multiTargets = [];
let multiMaxTargets = 0;
let multiCardIndex = -1;
// When set, the active MULTI_TARGETING is an ally swing (Raena etc.) instead
// of a player card play. The picker UX is identical (axe-style), but the
// resolver routes through resolveAllyAttack for each picked target.
let multiAllyAttacker = null;

// Feral Swipe state: multi-target where # targets = player shield
let feralSwipeMode = false;
let feralSwipeShieldGranted = 0;

// Barrage state (Magic Missiles: each shot resolves on click, card stays in hand)
let barrageMode = false;          // true = in barrage flow
let barrageShotsLeft = 0;         // remaining shots (0 = pre-pay phase)
let barrageShotsFired = 0;        // how many shots already fired (for cancel check)
let barrageShotsTotal = 0;        // total shots this barrage (barrage value + 1)
let barrageCardIndex = -1;        // index of MM in hand (stays there until done)
let barrageRechargedCard = null;  // card recharged as cost (for refund if cancelled)
let barrageShotDamage = 1;        // per-shot base damage from the MM card
let barrageBonusPoison = 0;       // intrinsic per-shot Poison (Poisoned Daggers "1 + Poison")
let barrageStaysInHand = false;   // card stays in hand on finish (no recharge/draw)
let barrageDrawOnFinish = 1;      // cards drawn when a non-stays barrage finishes (MM = 1, Blade Flurry = 0)
// Dragon Bone Bow variant: when true, each shot's base damage tapers
// down by (shotsFired - 1) from barrageShotDamage. Top damage = 4 →
// shot 1 = 4, shot 2 = 3, shot 3 = 2. Reset in finishBarrage /
// cancelBarrage alongside the rest of the barrage state.
let barrageDescending = false;
// Consumable on-attack buff snapshots — taken on the FIRST shot of a
// barrage so every subsequent shot in the same card play benefits.
// Mirrors the multi_damage / picker-flow pattern.
let barragePoisonStacks = 0;
let barrageEyeBonus = 0;
let barrageObsBonus = 0;
// Heroism / ice snapshots — consumed ONCE on shot 1 (logged + zeroed
// on the caster) and reused as a flat bonus / penalty on every
// subsequent shot in the same barrage. Matches the rest of the
// "one attack action, one consumption" snapshot family above so a
// single Heroism stack pumps every shot of the volley.
let barrageHeroism = 0;
let barrageIceReduction = 0;
let barrageIgnite = 0;

// Elemental-barrage state (Wand of Fire / Gravechill Shard: N staggered
// element shots, each picks its own target — same enemy or different).
// No pre-pay phase, no draw on finish; the card stays in hand because it
// carries stays_in_hand. `fireBarrageEffectType` is the effect each shot
// resolves ('apply_fire_multi' or 'apply_ice_multi') so the same flow
// handles both elements.
let fireBarrageMode = false;
let fireBarrageShotsLeft = 0;
let fireBarrageShotsFired = 0;
let fireBarrageCardIndex = -1;
let fireBarrageEffectType = 'apply_fire_multi';

// Arcane Beam state (click cards in hand to charge up bonus damage, click
// enemy to fire). Mirrors the barrage UX: card index is held, snapshots
// the hand for cancel/refund, and the fire path reads the count of
