function rollLootTable(id) {
  const table = LOOT_TABLES[id];
  if (!table) return null;
  const picks = Math.max(1, table.pickCount || 1);
  const distinct = !!table.distinct;
  const out = [];
  // When `distinct` is set, exclude already-picked entries from the
  // weighted pool so a multi-pick table (Harpy loot pickCount=2)
  // never hands out duplicates. Otherwise, multi-picks can repeat
  // (Cave Shroom's "2 of the same" drop relies on the no-distinct
  // default).
  const usedIdx = new Set();
  for (let n = 0; n < picks; n++) {
    const pool = distinct
      ? table.filter((_e, i) => !usedIdx.has(i))
      : table;
    if (pool.length === 0) break;
    const totalWeight = pool.reduce((s, e) => s + e.weight, 0);
    let roll = Math.random() * totalWeight;
    let picked = null;
    let pickedIdx = -1;
    for (let i = 0; i < pool.length; i++) {
      const entry = pool[i];
      roll -= entry.weight;
      if (roll <= 0) { picked = entry.creator(); pickedIdx = table.indexOf(entry); break; }
    }
    if (!picked) {
      const last = pool[pool.length - 1];
      picked = last.creator();
      pickedIdx = table.indexOf(last);
    }
    if (distinct && pickedIdx >= 0) usedIdx.add(pickedIdx);
    out.push(picked);
  }
  return out;
}

// Hand sizes per class
const CLASS_HAND_SIZE = {
  Paladin: 4, Ranger: 4, Wizard: 5, Rogue: 4, Warrior: 4, Druid: 4,
  // Path of the Necromancer — Wizard-sized hand (5) so the apprentice
  // still cycles through the sparse starter at a reasonable clip.
  Necromancer: 5,
};
const MAX_HAND_SIZE = 10;

// Push a loot card into the player's deck. Always lands in masterDeck;
// also goes to hand if there's room, otherwise it's recharged under the
// draw pile so the next combat (or refresh) picks it up. Without this
// gate, looting at a full hand silently overflows past MAX_HAND_SIZE.
function addLootedCard(card) {
  if (!player || !player.deck) return;
  // ccgQuest+ loot scaling — apply playerTierOffset to the looted
  // card so kills in a + run drop offset-up gear (a Rat at +1 hands
  // out tier-2 versions of the base loot). Skipped for companion
  // cards that were already swapped to a higher-tier creator by
  // resolveCompanionCardForTierOffset (no double bump).
  if (playerTierOffset > 0 && !card._companionTierSwapped) {
    applyGamePlusOffsetInPlace(card, playerTierOffset);
  }
  player.deck.masterDeck.push(card);
  if (player.deck.hand.length < MAX_HAND_SIZE) {
    player.deck.hand.push(card.copy ? card.copy() : card);
  } else {
    // Bottom of draw pile = next-to-last-drawn. unshift() puts at index
    // 0, which is the bottom (draw uses pop()).
    const copy = card.copy ? card.copy() : card;
    player.deck.drawPile.unshift(copy);
    addLog(`  Hand full — ${card.name} goes under the deck.`, Colors.GRAY, card);
  }
}

// === Asset Loading ===
const images = {};
let assetsLoaded = false;
// First-load progress (critical asset batch in loadAssets) — drives the
// boot loading bar so a player who clicks the URL cold isn't staring at
// a black screen for ~20s while the maps/backgrounds decode.
let _assetsLoadedCount = 0;
let _assetsTotalCount = 0;

function loadImage(id, src) {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      // Force eager decode so the browser doesn't defer bitmap decoding
      // to the first drawImage call (which causes visual glitches on powers)
      if (img.decode) {
        img.decode().then(() => { images[id] = img; resolve(img); })
                     .catch(() => { images[id] = img; resolve(img); });
      } else {
        images[id] = img;
        resolve(img);
      }
    };
    img.onerror = () => resolve(null);
    img.src = src;
  });
}

