function getEncounterBgImage(bgKey) {
  if (encounterBgImages[bgKey]) return encounterBgImages[bgKey];
  const filename = ENCOUNTER_BG_FILES[bgKey];
  if (!filename) return null;
  // Lazy load. Filenames prefixed with "Maps/" are pulled from the
  // shared map-art folder so encounter screens can reuse the same
  // image as the map view (e.g. Grand Hall).
  const img = new Image();
  img.onload = () => { encounterBgImages[bgKey] = img; };
  img.src = filename.startsWith('Maps/')
    ? `${BASE}assets/${filename}`
    : `${BASE}assets/Backgrounds/${filename}`;
  encounterBgImages[bgKey] = null; // mark as loading
  return null;
}

function getEncounterBg() {
  // 0. Spawn-time override — set by the chapter-7 random encounter
  // dispatcher so the golem/slime fight inherits the current map's
  // backdrop instead of its hard-coded obsidian-wastes default.
  // Cleared at encounter completion. Mirrors PY's encounter_bg_override.
  if (_encounterBgOverride) {
    const img = getEncounterBgImage(_encounterBgOverride);
    if (img) return img;
  }
  // 1. Per-text bgOverride (mirrors PY's EncounterText.bg_override).
  // The active text block can swap the encounter bg for one beat
  // (e.g. underground_river's "current picks up..." switches to the
  // rapids splash). Falls through if the override key is unknown.
  if (currentEncounter) {
    const phase = currentEncounter.currentPhase;
    if (phase && phase.phaseType === 'TEXT' && Array.isArray(phase.texts)) {
      const t = phase.texts[encounterTextIndex];
      if (t && t.bgOverride) {
        const img = getEncounterBgImage(t.bgOverride);
        if (img) return img;
      }
    }
    // 2. Encounter-specific background
    const bgKey = ENCOUNTER_BG_MAP[currentEncounter.id];
    if (bgKey) {
      const img = getEncounterBgImage(bgKey);
      if (img) return img;
    }
  }
  // 3. Fall back to map area image
  if (currentMap) {
    const node = currentMap.getCurrentNode();
    if (node) {
      const areaImg = images[`map_${node.mapArea}`];
      if (areaImg) return areaImg;
    }
  }
  return images.combat_bg || null;
}

function drawEncounterBg() {
  const bg = getEncounterBg();
  // Cinematic boss mode (Varimatras phase 3 combat): skip the
  // half-opacity black wash so the dragon backdrop reads as a
  // proper cinematic still. Also rock the whole sky when the
  // dragon swings — same shake math the per-target enemy card
  // shake uses, scaled up so the entire backdrop feels weighty.
  // Fires only when enemyArrow is active AND has no source creature
  // (= the dragon himself is the attacker; he has no creatures of
  // his own anyway, so this matches every dragon swing).
  const cinematicCombat = state === GameState.COMBAT
    && enemy && enemy._enemyId === 'varimatras';
  let shakeX = 0, shakeY = 0;
  if (cinematicCombat && enemyArrow && enemyArrow.timer > 0 && !enemyArrow.sourceCreature) {
    const si = Math.min(1, enemyArrow.timer / ENEMY_ARROW_DURATION) * 14;
    shakeX = Math.round((Math.random() - 0.5) * si * 2);
    shakeY = Math.round((Math.random() - 0.5) * si * 2);
  }
  if (bg) {
    if (shakeX || shakeY) {
      // Draw slightly oversized + offset so the shake never reveals
      // a black gutter at the screen edges.
      const pad = 24;
      ctx.drawImage(bg, shakeX - pad, shakeY - pad, SCREEN_WIDTH + pad * 2, SCREEN_HEIGHT + pad * 2);
    } else {
      ctx.drawImage(bg, 0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
    }
    if (!cinematicCombat) {
      ctx.fillStyle = 'rgba(0,0,0,0.5)';
      ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
    }
  } else {
    ctx.fillStyle = '#0e0e14';
    ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  }
}

function transitionToMap(mapCreator, startNode) {
  currentMap = mapCreator();
  visitedNodes = new Set();
  startNodeEncounter(startNode);
  // Chapter / area transitions are a natural autosave checkpoint.
  autosaveNow();
}

// Per-session GameMap cache (id → map instance). Lets bidirectional
// teleports between cities/regions preserve node state (which doors are
// open, which encounters are done, etc.) across cross-map hops.
// Cleared in startNewGame; the autosave snapshot captures the live map
// state independently so saves don't depend on the cache surviving.
const _mapCache = {};

function getOrCreateMap(mapId, factory) {
  if (!_mapCache[mapId]) {
    _mapCache[mapId] = factory();
    hydrateMapFromGlobalState(_mapCache[mapId]);
  }
  return _mapCache[mapId];
}

// When a map is created fresh — typically after a save+load wiped the
// in-memory cache, or on cross-map teleport into a map the player has
// already cleared — its nodes start with the factory defaults
// (everything locked, nothing done). Walk the node graph using the
// persistent globals (completedEncounters + story flags) to bring the
// state back to "post-progression" so the player isn't dropped onto an
// isolated, all-locked map.
function hydrateMapFromGlobalState(map) {
  if (!map) return;
  // First pass: any node whose encounter has been completed becomes
  // done + unlocked + un-hidden.
  for (const node of Object.values(map.nodes)) {
    if (node.encounterId && !node.isDone && completedEncounters.has(node.encounterId)) {
      node.isDone = true;
      node.isLocked = false;
      node.hiddenName = '';
      node.hiddenDescription = '';
    }
  }
  // Second pass: propagate `unlocks` from every done node so chain
  // unlocks (siege_gauntlet_1 → 2 → 3 → ...) are honored even when the
  // intermediate nodes have no completedEncounters entry yet. For
  // hide-until-visit maps (volcano family) we leave neighbor labels
  // hidden — visitedNodes already captures what was actually walked,
  // so unvisited neighbors stay ??? after a reload.
  const hideNeighbors = HIDE_UNTIL_VISIT_MAPS.has(map.id);
  for (const node of Object.values(map.nodes)) {
    if (node.isDone && Array.isArray(node.unlocks)) {
      for (const uid of node.unlocks) {
        const u = map.getNode(uid);
        if (u && u.isLocked) {
          u.isLocked = false;
          if (!hideNeighbors || visitedNodes.has(uid)) {
            u.hiddenName = '';
            u.hiddenDescription = '';
          }
        }
      }
    }
  }
  // Story-flag based unlocks for nodes without an encounter id.
  if (map.id === 'tharnag') {
    // North Pass opens once the throne audience is done — it has no
    // encounter so completedEncounters can't promote it.
    if (throneAudienceComplete) {
      const np = map.getNode('north_pass');
      if (np) { np.isLocked = false; np.hiddenName = ''; np.hiddenDescription = ''; }
    }
    // Siege Gauntlet nodes are locked behind one another; if the siege
    // is complete, the whole chain should be navigable.
    if (siegeComplete) {
      for (const id of ['siege_gauntlet_1', 'siege_gauntlet_2', 'siege_gauntlet_3', 'siege_gauntlet_dialog', 'tharnag_side_door']) {
        const n = map.getNode(id);
        if (n) {
          n.isLocked = false;
          n.hiddenName = '';
          n.hiddenDescription = '';
          if (n.encounterId && completedEncounters.has(n.encounterId)) n.isDone = true;
        }
      }
    }
  }
  // Tharnag interior — after the throne audience, the Personal
  // Quarters hallway + Artisan Hall lane (entry → hall → tavern +
  // smithy) all unlock. These nodes have no encounter id, so they
  // can't be promoted via completedEncounters alone.
  if (map.id === 'tharnag_interior' && throneAudienceComplete) {
    for (const id of ['quarters_hallway', 'personal_quarters_entry', 'artisan_hall_entry', 'artisan_hall', 'dwarven_tavern', 'dwarven_smithy']) {
      const n = map.getNode(id);
      if (n) {
        n.isLocked = false;
        n.hiddenName = '';
        n.hiddenDescription = '';
      }
    }
  }
  // Path of the Necromancer — bedroom trap-door reveal. The trap_door
  // node has its own encounter so the first-pass loop would only flip
  // it once the player has DESCENDED. We want the node visible (and
  // walkable) the moment the bedroom_trap_door dialog completes, so
  // a save in between still shows the open hatch beside the bed.
  if (map.id === 'necromancer_house' && completedEncounters.has('bedroom_trap_door')) {
    const td = map.getNode('trap_door');
    if (td) {
      td.isLocked = false;
      td.hiddenName = '';
      td.hiddenDescription = '';
    }
  }
  // Mithril Remedies — separate gate. The shop's dialog references
  // Valdrisa by name + assumes she's in the party, so the unlock waits
  // for valdrisaJoined (Personal Quarters rest → valdrisa_encounter)
  // rather than firing the moment the throne audience finishes.
  if (map.id === 'tharnag_interior' && valdrisaJoined) {
    const mr = map.getNode('mithril_remedies');
    if (mr) {
      mr.isLocked = false;
      mr.hiddenName = '';
      mr.hiddenDescription = '';
      mr._stateRevealed = true;
    }
  }
  // Post-dragon side quest unlocks on the Tharnag interior map.
  // Temple of Moradin doorway in the throne_room area opens the moment
  // the dragon is dead. _stateRevealed forces visibility regardless of
  // the player's current node.
  if (map.id === 'tharnag_interior' && dragonSlain) {
    const tmd = map.getNode('temple_moradin_door');
    if (tmd) {
      tmd.isLocked = false;
      tmd.hiddenName = '';
      tmd.hiddenDescription = '';
      tmd._stateRevealed = true;
    }
  }
  // Tharnag interior — Grand Hall Main Entrance unlocks once the
  // Mithril Remedies dialog has fired (the party now knows to head
  // out the front gate and up the Stairs of the Infinite to find
  // Olbrim). Pairs with the exterior Tharnag Main Door below.
  if (map.id === 'tharnag_interior' && mithrilRemediesVisited) {
    const n = map.getNode('grand_hall_main_entrance');
    if (n) {
      n.isLocked = false;
      n.hiddenName = '';
      n.hiddenDescription = '';
    }
  }
  // Tharnag exterior — the Main Door teleport target unlocks on
  // the same trigger. The pair lights up together so the player can
  // walk through immediately.
  if (map.id === 'tharnag' && mithrilRemediesVisited) {
    // Tharnag Main Door + the Stairs of the Infinite side quest
    // chain (Mountain Path → Bottom of the Infinite Stairs →
    // Climbing the Stairs) all open at the same moment so the
    // player can walk straight from the throne room out and start
    // climbing.
    for (const id of ['tharnag_main_door', 'mountain_path', 'bottom_stairs', 'climbing_stairs']) {
      const n = map.getNode(id);
      if (n) {
        n.isLocked = false;
        n.hiddenName = '';
        n.hiddenDescription = '';
      }
    }
  }
  // Obsidian Wastes: if the rest stop is complete, ensure the
  // Edge↔North shortcut is wired (handled separately in
  // transitionToObsidianWastes too, but defensive).
  if (map.id === 'obsidian_wastes' && labyrinthComplete) {
    const entry = map.getNode('wastes_entry');
    const north = map.getNode('wastes_north');
    if (entry && north) {
      if (!entry.connections.includes('wastes_north')) entry.connections.push('wastes_north');
      if (!north.connections.includes('wastes_entry')) north.connections.push('wastes_entry');
      north.isLocked = false;
      north.hiddenName = '';
      north.hiddenDescription = '';
    }
  }
  // Defensive: force canRevisit=false on nodes that the current map
  // definition treats as single-shot but that may carry stale
  // canRevisit=true on long-lived in-memory map instances (e.g. the
  // guild_hall fix landed mid-session). Cheap and idempotent.
  // Entries are NODE ids (the keys in map.nodes), not encounter ids.
  const SINGLE_SHOT_NODES = new Set([
    // Qualibaf arrival chain
    'guild_hall', 'city_north_gate', 'south_gate', 'north_crossroad',
    // Obsidian Wastes / Volcano
    'wastes_north', 'wastes_entry', 'volcano_approach',
    // Arriving-city / temple exit
    'river_crossing', 'cave_exit',
    // Sahuagin Flood Temple — single-shot beats. The boss_wing_entrance
    // ambush is repeatable (until the Baron dies, see repeatableUntil
    // on that node) and is intentionally NOT in this list. The
    // passage_ambush also stays repeatable per design.
    'piranha_pool', 'pool_edge', 'pool_exit',
    'temple_right', 'temple_left', 'temple_depths',
    'flooded_altar', 'old_god_statue', 'boss_wing_priest',
    // Lost Shrine — grants an ability card pick, must not re-fire.
    'lost_shrine',
  ]);
  for (const id of SINGLE_SHOT_NODES) {
    const n = map.getNode(id);
    if (n) n.canRevisit = false;
  }
}

// Older saves predate completedEncounters tracking for some encounter
// ids — players who completed those branches under earlier builds end
// up with story flags set but the global set missing entries. Replay
// the flag→encounter implications on load so hydrate has the data it
// needs to rebuild cross-map state.
//
// Built around the progression chain:
//   south_gate → guild_hall → city_north_gate → north_crossroad →
//   filibaf_entrance → forest_clearing → tharnag_entry →
//   siege_gauntlet_1/2/3 → siege_gauntlet_dialog → tharnag_side_door
//   → grand_hall_arrival → throne_audience → ...
// Any flag downstream implies every step upstream is done.
function seedCompletedEncountersFromFlags() {
  const add = id => completedEncounters.add(id);
  // Anything past the forest implies the player crossed Qualibaf city.
  const reachedNorthOfCity =
    forestCleared || siegeProgress > 0 || siegeComplete ||
    throneAudienceComplete || tharnagExitSeen || wastesNorthRestDone ||
    labyrinthComplete;
  if (reachedNorthOfCity) {
    // Qualibaf arrival chain — these are all single-shot story beats
    // the player must have cleared to leave the city.
    add('south_gate');
    add('guild_hall');
    add('city_north_gate');
    add('north_crossroad');
    // Sahuagin Flood Temple → cave exit → river crossing → south gate
    // is the only path into Qualibaf, so reaching the city implies all
    // of these mandatory beats cleared. Optional temple encounters
    // (conservatory_wing, dark_corridor, flooded_passage,
    // flooded_altar, old_god_statue, boss_wing_priest_combat) stay
    // off this list — they rely on the save's own completedEncounters.
    add('piranha_pool');
    add('sahuagin_sentinel');
    add('passage_ambush');
    add('cave_exit');
    add('river_crossing');
  }
  if (forestCleared) {
    add('forest_clearing');
    add('forest_edge');
    add('filibaf_entrance');
  }
  if (siegeProgress >= 1) add('siege_gauntlet_1');
  if (siegeProgress >= 2) add('siege_gauntlet_2');
  if (siegeProgress >= 3 || siegeComplete) {
    add('siege_gauntlet_3'); add('siege_gauntlet_dialog');
    // Seeding siege_gauntlet_3 implies tharnag_entry was cleared too.
    add('tharnag_arrival');
  }
  if (throneAudienceComplete) {
    add('throne_audience');
    add('tharnag_side_door');
    add('grand_hall_arrival');
  }
  if (tharnagExitSeen) add('tharnag_exit');
  if (valdrisaJoined) add('valdrisa_encounter');
  if (upperStairsReturnSeen) add('upper_stairs_return');
  if (quartersRested) add('quarters_rest');
  if (calmGroveRaenaJoined) add('calm_grove');
  if (wastesNorthRestDone || labyrinthComplete) {
    add('wastes_north');
    add('obsidian_wastes_arrival');
  }
  // Antiquity Shop: the cleared-shop variant relies on antiquityShopCleared.
  // Backfill from completedEncounters in case the flag was lost (older
  // save formats, partial state migrations) but the Mimic fight DID
  // complete. The flag also goes the other way — if the flag is set,
  // make sure the encounter id is in completedEncounters so hydrate
  // can keep the node looking done on fresh maps.
  if (completedEncounters.has('antiquity_shop') ||
      completedEncounters.has('antiquity_shop_cleared')) {
    antiquityShopCleared = true;
  }
  if (antiquityShopCleared) {
    add('antiquity_shop');
  }
}

// Sweep every Obsidian Shard out of every player pile at end of
// combat. Shards are per-combat junk shoved in by the Oracle's
// Curse — they should NOT bleed into the next fight.
function clearObsidianShardsFromDeck() {
  if (!player || !player.deck) return 0;
  let removed = 0;
  const filter = (arr) => {
    const next = [];
    for (const c of arr) {
      if (c && c.id === 'obsidian_shard_token') removed++;
      else next.push(c);
    }
    return next;
  };
  player.deck.hand = filter(player.deck.hand);
  player.deck.drawPile = filter(player.deck.drawPile);
  player.deck.discardPile = filter(player.deck.discardPile);
  player.deck.rechargePile = filter(player.deck.rechargePile);
  if (player.deck.playPile) player.deck.playPile = filter(player.deck.playPile);
  if (player.deck.damagePile) player.deck.damagePile = filter(player.deck.damagePile);
  if (player.deck.masterDeck) player.deck.masterDeck = filter(player.deck.masterDeck);
  if (removed > 0) addLog(`  ${removed} Obsidian Shard${removed === 1 ? '' : 's'} crumbled.`, Colors.GRAY);
  return removed;
}

// Sweep every Web token out of every player pile. Mirrors PY's
// game.py:4436-4440 cleanup that fires when the Forest Clearing
// encounter resolves (the player exits the maze for good). Returns the
// number of tokens removed for logging.
function clearWebTokensFromDeck() {
  if (!player || !player.deck) return 0;
  let removed = 0;
  const filter = (arr) => {
    const next = [];
    for (const c of arr) {
      if (c && c.id === 'web_token') removed++;
      else next.push(c);
    }
    return next;
  };
  player.deck.hand = filter(player.deck.hand);
  player.deck.drawPile = filter(player.deck.drawPile);
  player.deck.discardPile = filter(player.deck.discardPile);
  player.deck.rechargePile = filter(player.deck.rechargePile);
  if (player.deck.playPile) player.deck.playPile = filter(player.deck.playPile);
  if (player.deck.damagePile) player.deck.damagePile = filter(player.deck.damagePile);
  // masterDeck never holds Web tokens — they're added directly to draw —
  // but defensively scrub it anyway in case a stale save carries one.
  if (player.deck.masterDeck) player.deck.masterDeck = filter(player.deck.masterDeck);
  return removed;
}

