    enemy.deck = new Deck();
    for (let i = 0; i < 8; i++) enemy.deck.addCard(createRockyAppendage());
    // +2 starting armor per monster offset (5 → 7 → 9 …).
    enemy.baseArmor = 5 + 2 * (monsterTierOffset || 0);
    // Mirrors PY: obsidian_body — every attack peels 1 armor AND
