        const p = new Creature({
          name: 'Piranhas', attack: 0, maxHp: 1,
          bleedAttack: 1, haste: true, endOfTurnDeath: true,
          description: 'Atk + Bleed. Haste.\nDies at end of turn.\nOccasionally Edible.',
        });
