      const egg = new Creature({
        name: 'Unhatched Roc Egg',
        attack: 0, maxHp: 5, armor: 1,
        isCompanion: true,
        description: 'On Death: Hatch into a Roc Chick.\nEnd of Turn: Deal 1-3 damage to self.',
      });
