function handleHelpClick(x, y) {
  // < Back button positioned at bottom-right of the help panel —
  // rect must match drawHelpScreen's render so the click lands.
  const pw = 900, ph = 620;
  const px = (SCREEN_WIDTH - pw) / 2;
  const py = (SCREEN_HEIGHT - ph) / 2;
  const btnW = 200, btnH = 50;
  const btnX = px + pw - btnW - 16;
  const btnY = py + ph - btnH - 12;
  if (hitTest(x, y, { x: btnX, y: btnY, w: btnW, h: btnH })) {
    playSound('book_close');
    state = previousState || GameState.MAP;
  }
}

function drawHelpScreen() {
  // Draw the previous game state underneath so the game shows through
  const ps = previousState;
  if (ps === GameState.COMBAT || ps === GameState.TARGETING || ps === GameState.MODAL_SELECT || ps === GameState.REVIVE_SELECT) {
    drawCombat();
  } else if (ps === GameState.MAP) {
    drawMap();
  } else if (ps === GameState.ENCOUNTER_TEXT) {
    drawEncounterText();
  } else if (ps === GameState.ENCOUNTER_CHOICE) {
    drawEncounterChoice();
  }

  // Block all background interactions
  cardBadgeHitAreas.length = 0;
  iconHitAreas.length = 0;
  menuButtons.length = 0;

  // Dim overlay (matches py game ~78%)
  ctx.fillStyle = 'rgba(0,0,0,0.78)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);

  // Panel — dark brown to match py game (40, 35, 30) with warm gold border (180, 160, 120)
  const pw = 900, ph = 620;
  const px = (SCREEN_WIDTH - pw) / 2;
  const py = (SCREEN_HEIGHT - ph) / 2;
  ctx.fillStyle = 'rgba(40, 35, 30, 0.97)';
  ctx.fillRect(px, py, pw, ph);
  ctx.strokeStyle = '#b4a078'; // warm gold (180, 160, 120)
  ctx.lineWidth = 2;
  ctx.strokeRect(px, py, pw, ph);

  // Title
  ctx.fillStyle = '#dcc896'; // warmer gold (220, 200, 150)
  ctx.font = 'bold 28px Georgia, serif';
  ctx.textAlign = 'center';
  ctx.fillText('Game Reference', Math.round(SCREEN_WIDTH / 2), Math.round(py + 40));

  // Content area
  const contentTop = py + 60;
  const contentBottom = py + ph - 60;
  const contentH = contentBottom - contentTop;
  const innerW = pw - 60;

  // Clip
  ctx.save();
  ctx.beginPath();
  ctx.rect(px + 10, contentTop, pw - 20, contentH);
  ctx.clip();

  let y = contentTop + 16 - helpScrollY;
  ctx.textAlign = 'left';
  const sectionGap = 14;
  const lineGap = 3;
  const fontSize = 16;
  for (const section of HELP_CONTENT) {
    // Section header in warm gold, sits adjacent to its description block
    ctx.fillStyle = '#dcc896';
    ctx.font = 'bold 19px Georgia, serif';
    ctx.fillText(`-- ${section.title} --`, Math.round(px + 30), Math.round(y + 14));
    y += 24;
    // Items rendered with inline icons in the item's color
    for (const item of section.items) {
      const itemColor = item.color || HELP_WHITE;
      const usedH = drawIconTextLeft(item.text, px + 50, y, innerW - 40, fontSize, itemColor);
      y += usedH + lineGap;
    }
    y += sectionGap;
  }
  // Calculate max scroll
  const totalH = (y + helpScrollY) - (contentTop + 16);
  const maxScroll = Math.max(0, totalH - contentH);
  if (helpScrollY > maxScroll) helpScrollY = maxScroll;

  ctx.restore();

  // Scrollbar if content overflows
  if (maxScroll > 0) {
    const sbW = 12;
    const sbX = px + pw - sbW - 6;
    ctx.fillStyle = 'rgba(30, 28, 25, 0.9)';
    ctx.fillRect(sbX, contentTop, sbW, contentH);
    const thumbRatio = contentH / totalH;
    const thumbH = Math.max(20, contentH * thumbRatio);
    const thumbY = contentTop + (helpScrollY / maxScroll) * (contentH - thumbH);
    ctx.fillStyle = '#8c8068';
    ctx.fillRect(sbX, thumbY, sbW, thumbH);
    ctx.strokeStyle = '#b4a078';
    ctx.lineWidth = 1;
    ctx.strokeRect(sbX, thumbY, sbW, thumbH);
  }

  // < Back button (bottom-right of panel) — same wooden-plank style
  // as the inventory back button, sized to fit the help panel.
  const btnW = 200, btnH = 50;
  const btnX = px + pw - btnW - 16;
  const btnY = py + ph - btnH - 12;
  drawStyledButton(btnX, btnY, btnW, btnH, '< Back', null, 'large', 20);
}

// ============================================================
// OPTIONS SCREEN
// ============================================================

function handleOptionsClick(x, y) {
  const boxW = 440, boxH = 740;
  const boxX = (SCREEN_WIDTH - boxW) / 2, boxY = (SCREEN_HEIGHT - boxH) / 2;
  const btnW = 280, btnH = 50;
  const btnX = boxX + (boxW - btnW) / 2;
  const sliderX = btnX + 20, sliderW = btnW - 40;
  const sliderH = 12;

  // Sound toggle
  const sndY = boxY + 80;
  if (hitTest(x, y, { x: btnX, y: sndY, w: btnW, h: btnH })) {
    toggleSound();
    playSound('click');
    saveOptions();
    return;
  }
  // SFX volume slider
  const sfxSliderY = sndY + btnH + 16;
  if (hitTest(x, y, { x: sliderX - 4, y: sfxSliderY - 4, w: sliderW + 8, h: sliderH + 8 })) {
    const pct = Math.max(0, Math.min(1, (x - sliderX) / sliderW));
    setSoundVolume(pct);
    playSound('click');
    saveOptions();
    return;
  }
  // Music toggle
  const musY = sfxSliderY + sliderH + 38;
  if (hitTest(x, y, { x: btnX, y: musY, w: btnW, h: btnH })) {
    toggleMusic();
    playSound('click');
    saveOptions();
    return;
  }
  // Music volume slider
  const musSliderY = musY + btnH + 16;
  if (hitTest(x, y, { x: sliderX - 4, y: musSliderY - 4, w: sliderW + 8, h: sliderH + 8 })) {
    const pct = Math.max(0, Math.min(1, (x - sliderX) / sliderW));
    setMusicVolume(pct);
    playSound('click');
    saveOptions();
    return;
  }
  // Run Fast toggle
  const rfY = musSliderY + sliderH + 38;
  if (hitTest(x, y, { x: btnX, y: rfY, w: btnW, h: btnH })) {
    runFast = !runFast;
    playSound('click');
    saveOptions();
    return;
  }
  // Enemy speed picker — three side-by-side pills.
  const espY = rfY + btnH + 16;
  const espH = btnH;
  const pillW = Math.floor((btnW - 8) / 3);
  const speeds = ['slow', 'medium', 'fast'];
  for (let i = 0; i < 3; i++) {
    const px = btnX + i * (pillW + 4);
    if (hitTest(x, y, { x: px, y: espY, w: pillW, h: espH })) {
      enemySpeed = speeds[i];
      enemySpeedExplicit = true; // lock the player's choice
      playSound('click');
      saveOptions();
      return;
    }
  }
  // Tutorial toggle + Reset Tutorial Progress button.
  const tutY = espY + espH + 16;
  if (hitTest(x, y, { x: btnX, y: tutY, w: btnW, h: btnH })) {
    setTutorialEnabled(!_tutorialEnabled);
    playSound('click');
    return;
  }
  const resetH = 32;
  const resetY = tutY + btnH + 8;
  const resetW = 220;
  const resetX = btnX + (btnW - resetW) / 2;
  if (hitTest(x, y, { x: resetX, y: resetY, w: resetW, h: resetH })) {
    resetTutorialProgress();
    showStyledToast('Tutorial progress reset.', 'recharge', 1800);
    playSound('click');
    return;
  }
  // End-Turn warn-allies toggle.
  const etwY = resetY + resetH + 16;
  if (hitTest(x, y, { x: btnX, y: etwY, w: btnW, h: btnH })) {
    _endTurnWarnAllies = !_endTurnWarnAllies;
    playSound('click');
    saveOptions();
    return;
  }
  // Back button
  const backY = boxY + boxH - btnH - 20;
  if (hitTest(x, y, { x: btnX, y: backY, w: btnW, h: btnH })) {
    playSound('book_close');
    state = optionsReturnState || GameState.MENU;
    return;
  }
}

function drawOptionsScreen() {
  if (optionsReturnState === GameState.INGAME_MENU) {
    drawIngameMenu();
  } else if (optionsReturnState === GameState.MENU) {
    drawMenu();
  }
  ctx.fillStyle = 'rgba(0,0,0,0.7)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  menuButtons.length = 0;

  const boxW = 440, boxH = 740;
  const boxX = (SCREEN_WIDTH - boxW) / 2, boxY = (SCREEN_HEIGHT - boxH) / 2;
  ctx.fillStyle = 'rgba(45, 45, 55, 0.95)';
  ctx.fillRect(boxX, boxY, boxW, boxH);
  ctx.strokeStyle = Colors.GOLD;
  ctx.lineWidth = 3;
  ctx.strokeRect(boxX, boxY, boxW, boxH);

  ctx.shadowColor = 'rgba(0,0,0,0.9)';
  ctx.shadowBlur = 6;
  ctx.shadowOffsetY = 2;
  ctx.fillStyle = Colors.GOLD;
  ctx.font = 'bold 34px Georgia, serif';
  ctx.textAlign = 'center';
  ctx.fillText('Options', SCREEN_WIDTH / 2, boxY + 50);
  ctx.shadowColor = 'transparent';
  ctx.shadowBlur = 0;
  ctx.shadowOffsetY = 0;

  const btnW = 280, btnH = 50;
  const btnX = boxX + (boxW - btnW) / 2;
  const sliderX = btnX + 20, sliderW = btnW - 40;
  const sliderH = 12;

  // Helper: draw a labelled volume bar with thumb at value 0..1.
  const drawVolBar = (sx, sy, sw, sh, value, label) => {
    ctx.fillStyle = '#333';
    ctx.fillRect(sx, sy, sw, sh);
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 1;
    ctx.strokeRect(sx, sy, sw, sh);
    ctx.fillStyle = Colors.GOLD;
    ctx.fillRect(sx, sy, sw * value, sh);
    const thumb = sx + sw * value;
    ctx.fillStyle = Colors.WHITE;
    ctx.fillRect(thumb - 4, sy - 3, 8, sh + 6);
    ctx.fillStyle = '#ccc';
    ctx.font = '13px sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(label, btnX + btnW / 2, sy + sh + 18);
  };

  // Sound toggle
  const sndY = boxY + 80;
  const sndLabel = isSoundEnabled() ? '✓ Sound On' : 'Sound Off';
  drawStyledButton(btnX, sndY, btnW, btnH, sndLabel, null, 'large', 20);
  menuButtons.pop();
  if (isSoundEnabled()) {
    ctx.strokeStyle = Colors.GREEN;
    ctx.lineWidth = 2;
    ctx.strokeRect(btnX + 1, sndY + 1, btnW - 2, btnH - 2);
  }
  // SFX volume
  const sfxSliderY = sndY + btnH + 16;
  drawVolBar(sliderX, sfxSliderY, sliderW, sliderH, getSoundVolume(),
             `SFX: ${Math.round(getSoundVolume() * 100)}%`);

  // Music toggle
  const musY = sfxSliderY + sliderH + 38;
  const musLabel = isMusicEnabled() ? '✓ Music On' : 'Music Off';
  drawStyledButton(btnX, musY, btnW, btnH, musLabel, null, 'large', 20);
  menuButtons.pop();
  if (isMusicEnabled()) {
    ctx.strokeStyle = Colors.GREEN;
    ctx.lineWidth = 2;
    ctx.strokeRect(btnX + 1, musY + 1, btnW - 2, btnH - 2);
  }
  // Music volume
  const musSliderY = musY + btnH + 16;
  drawVolBar(sliderX, musSliderY, sliderW, sliderH, getMusicVolume(),
             `Music: ${Math.round(getMusicVolume() * 100)}%`);

  // Run Fast toggle
  const rfY = musSliderY + sliderH + 38;
  const rfLabel = runFast ? '✓ Run Fast' : 'Run Fast';
  drawStyledButton(btnX, rfY, btnW, btnH, rfLabel, null, 'large', 20);
  menuButtons.pop();
  if (runFast) {
    ctx.strokeStyle = Colors.GREEN;
    ctx.lineWidth = 2;
    ctx.strokeRect(btnX + 1, rfY + 1, btnW - 2, btnH - 2);
  }

  // Enemy speed: 3 small side-by-side pills (Slow / Medium / Fast).
  const espY = rfY + btnH + 16;
  const espH = btnH;
  const pillW = Math.floor((btnW - 8) / 3);
  const labels = ['Slow', 'Medium', 'Fast'];
  const speeds = ['slow', 'medium', 'fast'];
  for (let i = 0; i < 3; i++) {
    const px = btnX + i * (pillW + 4);
    drawStyledButton(px, espY, pillW, espH, labels[i], null, 'small', 16);
    menuButtons.pop();
    if (enemySpeed === speeds[i]) {
      ctx.strokeStyle = Colors.GREEN;
      ctx.lineWidth = 2;
      ctx.strokeRect(px + 1, espY + 1, pillW - 2, espH - 2);
    }
  }
  // Header above the pills so the row reads as a single control group.
  ctx.fillStyle = '#ccc';
  ctx.font = '12px sans-serif';
  ctx.textAlign = 'center';
  ctx.fillText('Enemy Animation Speed', btnX + btnW / 2, espY - 4);

  // Tutorial toggle + reset. Reset sits as a small secondary
  // button directly below the toggle so the layout reads as one
  // grouped control. Reset is enabled regardless of toggle state.
  const tutY = espY + espH + 16;
  const tutLabel = _tutorialEnabled ? '✓ Tutorial On' : 'Tutorial Off';
  drawStyledButton(btnX, tutY, btnW, btnH, tutLabel, null, 'large', 20);
  menuButtons.pop();
  if (_tutorialEnabled) {
    ctx.strokeStyle = Colors.GREEN;
    ctx.lineWidth = 2;
    ctx.strokeRect(btnX + 1, tutY + 1, btnW - 2, btnH - 2);
  }
  // Reset button — same styled-button look as the other options,
  // just narrower / shorter so it reads as a secondary control
  // grouped under the toggle.
  const resetH = 32;
  const resetY = tutY + btnH + 8;
  const resetW = 220;
  const resetX = btnX + (btnW - resetW) / 2;
  drawStyledButton(resetX, resetY, resetW, resetH, 'Reset Tutorial', null, 'small', 14);
  menuButtons.pop();

  // End Turn warning toggle — warn when the player tries to end the
  // turn with un-swung allies on the field. Default on.
  const etwY = resetY + resetH + 16;
  const etwLabel = _endTurnWarnAllies ? '✓ Warn: Idle Allies' : 'Warn: Idle Allies';
  drawStyledButton(btnX, etwY, btnW, btnH, etwLabel, null, 'large', 20);
  menuButtons.pop();
  if (_endTurnWarnAllies) {
    ctx.strokeStyle = Colors.GREEN;
    ctx.lineWidth = 2;
    ctx.strokeRect(btnX + 1, etwY + 1, btnW - 2, btnH - 2);
  }

  // Back button
  const backY = boxY + boxH - btnH - 20;
  drawStyledButton(btnX, backY, btnW, btnH, '< Back', null, 'large', 20);
  menuButtons.pop();

  ctx.textAlign = 'left';
}

// ============================================================
// IN-GAME MENU
// ============================================================

function getIngameMenuBtnRects() {
  const btnW = 280, btnH = 56, gap = 12;
  const items = [
    { label: 'Resume', action: 'resume' },
    { label: 'Save Game', action: 'save', enabled: previousState === GameState.MAP },
    { label: 'Load Game', action: 'load' },
    { label: 'Options', action: 'options' },
    { label: 'Main Menu', action: 'quit' },
  ];
  const totalH = items.length * (btnH + gap) - gap;
  const startX = (SCREEN_WIDTH - btnW) / 2;
  const startY = (SCREEN_HEIGHT - totalH) / 2 + 20;
  return items.map((item, i) => ({
    x: startX, y: startY + i * (btnH + gap), w: btnW, h: btnH, ...item,
  }));
}

function handleIngameMenuClick(x, y) {
  // Quit-to-main confirm dialog — if it's open, eat all other
  // clicks and route to the Yes/No buttons.
  if (_ingameMenuConfirmQuit) {
    const m = getQuitConfirmRects();
    if (hitTest(x, y, m.yes)) {
      playSound('click');
      _ingameMenuConfirmQuit = false;
      state = GameState.MENU;
      player = null;
      currentMap = null;
      currentEncounter = null;
      // Quit-without-saving from a Game+ run = the source slot was
      // never committed. Clear the deferred consumption so the next
      // Game+ launch (or this same one re-loaded) finds the slot
      // still available. Necessary even if autosave fired earlier
      // because that already stamped the flag — the clear here just
      // avoids leaking the variable into a different class's launch.
      _pendingGamePlusConsumeSlot = null;
      // Reset the menu music so the heroic title theme actually
      // starts playing again on quit. pauseMusic muted the gameplay
      // track when the in-game menu opened; without these flag
      // resets, resumeMusic just unmutes the combat music (which is
      // still cued up) under the title screen instead of switching
      // back to the menu theme. stopMusic kills the cued combat
      // track outright; startMenuMusicIfNeeded re-arms the heroic
      // loop. Mirrors what startNewGame does on the way IN to the
      // run, just in reverse.
      try { stopMusic(); } catch (_) {}
      _menuMusicStarted = false;
      _hasEnteredCombat = false;
      _lastMusicArea = null;
      _lastMusicNodeId = null;
      startMenuMusicIfNeeded();
      return;
    }
    if (hitTest(x, y, m.no) || !hitTest(x, y, m.panel)) {
      // No, or click outside the panel — dismiss.
      playSound('click');
      _ingameMenuConfirmQuit = false;
      return;
    }
    // Click inside the panel but not on a button — ignore.
    return;
  }
  for (const btn of getIngameMenuBtnRects()) {
    if (!hitTest(x, y, btn)) continue;
    if (btn.action === 'resume') {
      playSound('book_close');
      state = previousState || GameState.MAP;
    } else if (btn.action === 'save' && btn.enabled) {
      playSound('book_open');
      saveLoadReturnState = GameState.INGAME_MENU;
      state = GameState.SAVE_GAME;
    } else if (btn.action === 'load') {
      playSound('book_open');
      saveLoadReturnState = GameState.INGAME_MENU;
      loadTab = 'manual';
      loadSelectedIndex = -1;
      refreshLoadEntries();
      state = GameState.LOAD_GAME;
    } else if (btn.action === 'options') {
      playSound('book_open');
      optionsReturnState = state;
      state = GameState.OPTIONS_SCREEN;
    } else if (btn.action === 'help') {
      playSound('book_open');
      helpScrollY = 0;
      state = GameState.HELP_SCREEN;
    } else if (btn.action === 'quit') {
      // Defer to a Yes/No confirm — quitting drops the player back
      // to the main menu and wipes the in-memory run. Autosaves are
      // still safe, but mid-encounter / mid-combat state would be
      // lost (the autosave reload would put them at the last node).
      _ingameMenuConfirmQuit = true;
    }
    return;
  }
}

// Quit-to-main confirm modal — module-scoped flag so drawIngameMenu
// can layer the dialog on top of the regular menu buttons, and the
// click handler knows when to intercept.
let _ingameMenuConfirmQuit = false;

function getQuitConfirmRects() {
  const panelW = 480;
  const panelH = 220;
  const px = Math.round((SCREEN_WIDTH - panelW) / 2);
  const py = Math.round((SCREEN_HEIGHT - panelH) / 2);
  const btnW = 160;
  const btnH = 50;
  const btnGap = 24;
  const btnY = py + panelH - btnH - 24;
  const yesX = px + Math.round((panelW - btnW * 2 - btnGap) / 2);
  const noX = yesX + btnW + btnGap;
  return {
    panel: { x: px, y: py, w: panelW, h: panelH },
    yes: { x: yesX, y: btnY, w: btnW, h: btnH },
    no: { x: noX, y: btnY, w: btnW, h: btnH },
  };
}

function drawQuitConfirmDialog() {
  if (!_ingameMenuConfirmQuit) return;
  const r = getQuitConfirmRects();
  // Extra dim over the existing in-game menu dim.
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  // Panel.
  ctx.fillStyle = 'rgba(28, 26, 36, 0.97)';
  ctx.fillRect(r.panel.x, r.panel.y, r.panel.w, r.panel.h);
  ctx.strokeStyle = Colors.GOLD;
  ctx.lineWidth = 3;
  ctx.strokeRect(r.panel.x, r.panel.y, r.panel.w, r.panel.h);
  // Title.
  ctx.fillStyle = Colors.GOLD;
  ctx.font = 'bold 22px Georgia, serif';
  ctx.textAlign = 'center';
  ctx.fillText('Quit to Main Menu?', r.panel.x + r.panel.w / 2, r.panel.y + 50);
  // Body.
  ctx.fillStyle = '#e8d59a';
  ctx.font = '15px Georgia, serif';
  ctx.fillText('Unsaved progress in this run will be lost.', r.panel.x + r.panel.w / 2, r.panel.y + 90);
  ctx.fillStyle = '#bdb59a';
  ctx.font = 'italic 13px Georgia, serif';
  ctx.fillText('Save first from the menu if you want to keep it.', r.panel.x + r.panel.w / 2, r.panel.y + 115);
  ctx.textAlign = 'left';
  // Buttons — same wooden-plank style as the other menus.
  drawStyledButton(r.yes.x, r.yes.y, r.yes.w, r.yes.h, 'Yes', null, 'large', 20);
  drawStyledButton(r.no.x, r.no.y, r.no.w, r.no.h, 'No', null, 'large', 20);
}

function drawIngameMenu() {
  // Draw the previous game state underneath so the game shows through
  const ps = previousState;
  if (ps === GameState.COMBAT || ps === GameState.TARGETING || ps === GameState.MODAL_SELECT || ps === GameState.REVIVE_SELECT) {
    drawCombat();
  } else if (ps === GameState.MAP) {
    drawMap();
  } else if (ps === GameState.ENCOUNTER_TEXT) {
    drawEncounterText();
  } else if (ps === GameState.ENCOUNTER_CHOICE) {
    drawEncounterChoice();
  }

  // Block all background interactions: clear hover/click hit areas registered by the underlying game
  cardBadgeHitAreas.length = 0;
  iconHitAreas.length = 0;
  menuButtons.length = 0;

  // Full semi-transparent black overlay
  ctx.fillStyle = 'rgba(0,0,0,0.6)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);

  // Menu box (grey with gold border, matches load screen)
  const boxW = 440, boxH = 460;
  const boxX = (SCREEN_WIDTH - boxW) / 2, boxY = (SCREEN_HEIGHT - boxH) / 2;
  ctx.fillStyle = 'rgba(45, 45, 55, 0.95)';
  ctx.fillRect(boxX, boxY, boxW, boxH);
  ctx.strokeStyle = Colors.GOLD;
  ctx.lineWidth = 3;
  ctx.strokeRect(boxX, boxY, boxW, boxH);

  // Title in gold with shadow
  ctx.shadowColor = 'rgba(0,0,0,0.9)';
  ctx.shadowBlur = 6;
  ctx.shadowOffsetY = 2;
  ctx.fillStyle = Colors.GOLD;
  ctx.font = 'bold 38px Georgia, serif';
  ctx.textAlign = 'center';
  ctx.fillText('PAUSED', SCREEN_WIDTH / 2, boxY + 55);
  ctx.shadowColor = 'transparent';
  ctx.shadowBlur = 0;
  ctx.shadowOffsetY = 0;

  // Buttons using the wooden plank styled button (sprite from End Turn button)
  for (const btn of getIngameMenuBtnRects()) {
    const enabled = btn.enabled !== false;
    if (!enabled) ctx.globalAlpha = 0.45;
    drawStyledButton(btn.x, btn.y, btn.w, btn.h, btn.label, null, 'large', 22);
    if (!enabled) {
      ctx.globalAlpha = 1;
      // Show "(map only)" hint below
      ctx.fillStyle = '#aaa';
      ctx.font = '12px sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('(map only)', btn.x + btn.w / 2, btn.y + btn.h + 12);
    }
    // Click is handled by handleIngameMenuClick using getIngameMenuBtnRects directly
    menuButtons.pop();
  }

  // Quit-to-main Yes/No confirm on top of the menu buttons.
  drawQuitConfirmDialog();

  ctx.textAlign = 'left';
}

// ============================================================
// FADE TRANSITIONS
// ============================================================

function startFade(callback, targetState = null, speed = 8) {
  fadeAlpha = 0;
  fadePhase = 'out';
  fadeCallback = callback;
  fadeTargetState = targetState;
  fadeSpeed = speed;
  state = GameState.FADING;
}

function updateFade(dt) {
  if (!fadePhase) return;
  const step = fadeSpeed * (dt / 16); // normalize to ~60fps
  if (fadePhase === 'out') {
    fadeAlpha = Math.min(255, fadeAlpha + step);
    if (fadeAlpha >= 255) {
      if (fadeCallback) fadeCallback();
      fadeCallback = null;
      if (fadeTargetState) state = fadeTargetState;
      fadeTargetState = null;
      fadePhase = 'in';
    }
  } else if (fadePhase === 'in') {
    fadeAlpha = Math.max(0, fadeAlpha - step);
    if (fadeAlpha <= 0) {
      fadePhase = '';
      fadeAlpha = 0;
    }
  }
}

// ============================================================
// TITLE CARDS
// ============================================================

function showTitleCard(title, subtitle = '', callback = null) {
  titleCardText = title;
  titleCardSubtitle = subtitle;
  titleCardAlpha = 0;
  titleCardPhase = 'in';
  titleCardTimer = 0;
  titleCardCallback = callback;
  state = GameState.TITLE_CARD;
}

function updateTitleCard(dt) {
  if (!titleCardPhase) return;
  const step = 4 * (dt / 16);
  if (titleCardPhase === 'in') {
    titleCardAlpha = Math.min(255, titleCardAlpha + step);
    if (titleCardAlpha >= 255) {
      titleCardPhase = 'hold';
      titleCardTimer = 2000; // 2 seconds hold
    }
  } else if (titleCardPhase === 'hold') {
    titleCardTimer -= dt;
    if (titleCardTimer <= 0) {
      titleCardPhase = 'out';
    }
  } else if (titleCardPhase === 'out') {
    titleCardAlpha = Math.max(0, titleCardAlpha - step);
    if (titleCardAlpha <= 0) {
      titleCardPhase = '';
      if (titleCardCallback) titleCardCallback();
      titleCardCallback = null;
    }
  }
}

function dismissTitleCard() {
  if (titleCardPhase === 'hold' || titleCardPhase === 'in') {
    titleCardPhase = 'out';
    titleCardAlpha = 255;
  }
}

// ============================================================
// END CREDITS — fires after the post-Varimatras sleep beat.
// Slow-scrolls the credit roll upward from below the screen, then
// auto-returns to the main menu. Click anywhere to skip to menu.
// ============================================================

// Roughly 24 px/sec at 60 fps. Tuned to a "Star Wars crawl" pace
// — long enough to read each block, short enough not to drag.
const END_CREDITS_SCROLL_PX_PER_FRAME = 0.4;
const END_CREDITS_LINE_HEIGHT = 30;
const END_CREDITS_TAIL_PAD = 180; // extra empty space after the last line before auto-exit
let endCreditsScrollY = 0;
let endCreditsContentH = 0;
let endCreditsLines = [];

// Lines: { text, style }
