function startEndCredits() {
  endCreditsLines = END_CREDITS_TEMPLATE.slice();
  endCreditsContentH = endCreditsLines.length * END_CREDITS_LINE_HEIGHT;
  // Start the credits below the screen so the first line scrolls in
  // from the bottom edge.
  endCreditsScrollY = SCREEN_HEIGHT;
  state = GameState.END_CREDITS;
}

function updateEndCredits() {
  endCreditsScrollY -= END_CREDITS_SCROLL_PX_PER_FRAME;
  // Done when the LAST line has scrolled off the top.
  if (endCreditsScrollY < -(endCreditsContentH + END_CREDITS_TAIL_PAD)) {
    finishEndCredits();
  }
}

function finishEndCredits() {
  endCreditsLines = [];
  endCreditsScrollY = 0;
  endCreditsContentH = 0;
  state = GameState.MENU;
}

// === Necromancer-class unlock splash (Path of the Necromancer finale) ===
// Entered from advanceEncounterPhase when the Abbey Courtyard epilogue
// completes. Shows the reward title + older-necromancer portrait over
// the frontier-road backdrop, then fades to the main menu on click.
let _necroUnlockExiting = false;
let _necroUnlockFade = 0;

function returnToMenuFromNecroUnlock() {
  _necroUnlockExiting = false;
  _necroUnlockFade = 0;
  // Tear the finished run down the same way "Quit to Menu" does so the
  // title screen comes back clean and the menu theme restarts.
  state = GameState.MENU;
  player = null;
  currentMap = null;
  currentEncounter = null;
  _encounterBgOverride = null;
  // Music: the heroic theme started on the Gravekeeper's death IS the
  // menu track, so leave it playing for a seamless hand-off instead of
  // stopping + restarting it. combatVictory already set
  // _menuMusicStarted, so startMenuMusicIfNeeded is a no-op here; the
  // call is a safety net in case the track somehow stopped.
  _hasEnteredCombat = false;
  _lastMusicArea = null;
  _lastMusicNodeId = null;
  startMenuMusicIfNeeded();
}

function handleNecromancerUnlockClick() {
  if (_necroUnlockExiting) return;
  playSound('click');
  _necroUnlockExiting = true;
}

function drawNecromancerUnlock() {
  // Last backdrop — the frontier-road / story-selector art the
  // epilogue ended on.
  const bg = images['quest_select_bg'];
  if (bg) ctx.drawImage(bg, 0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  else { ctx.fillStyle = '#0a0a12'; ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT); }
  ctx.fillStyle = 'rgba(0,0,0,0.6)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);

  ctx.textAlign = 'center';
  ctx.fillStyle = Colors.GOLD;
  ctx.font = 'bold 28px serif';
  ctx.fillText('You have unlocked', SCREEN_WIDTH / 2, SCREEN_HEIGHT * 0.15);
  ctx.font = 'bold 52px serif';
  ctx.fillText('THE NECROMANCER CLASS', SCREEN_WIDTH / 2, SCREEN_HEIGHT * 0.235);

  const portrait = images['necromancer_unlock_portrait'];
  if (portrait && portrait.width) {
    const maxH = SCREEN_HEIGHT * 0.5;
    const scale = maxH / portrait.height;
    const pw = portrait.width * scale;
    const ph = portrait.height * scale;
    const px = (SCREEN_WIDTH - pw) / 2;
    const py = SCREEN_HEIGHT * 0.3;
    ctx.drawImage(portrait, px, py, pw, ph);
    ctx.strokeStyle = Colors.GOLD;
    ctx.lineWidth = 3;
    ctx.strokeRect(px, py, pw, ph);
  }

  ctx.fillStyle = Colors.WHITE;
  ctx.font = '18px sans-serif';
  ctx.fillText('Click to continue', SCREEN_WIDTH / 2, SCREEN_HEIGHT * 0.93);
  ctx.textAlign = 'left';

  // Click-triggered fade-out to the main menu.
  if (_necroUnlockExiting) {
    _necroUnlockFade = Math.min(1, _necroUnlockFade + 0.035);
    ctx.fillStyle = `rgba(0,0,0,${_necroUnlockFade})`;
    ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
    if (_necroUnlockFade >= 1) returnToMenuFromNecroUnlock();
  }
}

function drawEndCredits() {
  // Solid black backdrop — credits-style.
  ctx.fillStyle = '#000';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  ctx.textAlign = 'center';
  ctx.textBaseline = 'top';
  let y = Math.floor(endCreditsScrollY);
  for (const line of endCreditsLines) {
    if (y > -END_CREDITS_LINE_HEIGHT && y < SCREEN_HEIGHT) {
      const cx = SCREEN_WIDTH / 2;
      if (line.style === 'header') {
        ctx.fillStyle = Colors.GOLD;
        ctx.font = 'bold 38px Georgia, serif';
        ctx.save();
        ctx.shadowColor = 'rgba(0,0,0,0.95)';
        ctx.shadowBlur = 6;
        ctx.fillText(line.text, cx, y);
        ctx.restore();
      } else if (line.style === 'section') {
        ctx.fillStyle = Colors.GOLD;
        ctx.font = 'bold 22px Georgia, serif';
        ctx.fillText(line.text, cx, y);
      } else if (line.style === 'role') {
        ctx.fillStyle = '#dde3ec';
        ctx.font = '15px "Courier New", monospace';
        ctx.fillText(line.text, cx, y);
      } else if (line.style === 'name') {
        ctx.fillStyle = '#ffe9a0';
        ctx.font = 'bold 22px Georgia, serif';
        ctx.fillText(line.text, cx, y);
      } else if (line.style === 'thanks') {
        ctx.fillStyle = '#c8d0d8';
        ctx.font = 'italic 16px Georgia, serif';
        ctx.fillText(line.text, cx, y);
      }
    }
    y += END_CREDITS_LINE_HEIGHT;
  }
  // Skip hint at the bottom — fades in a few seconds after start so
  // it doesn't compete with the first lines crossing the screen.
  if (endCreditsScrollY < SCREEN_HEIGHT - 60) {
    ctx.fillStyle = 'rgba(180,180,200,0.55)';
    ctx.font = 'italic 12px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'bottom';
    ctx.fillText('Click to skip to menu', SCREEN_WIDTH / 2, SCREEN_HEIGHT - 12);
  }
  ctx.textAlign = 'left';
  ctx.textBaseline = 'alphabetic';
}

function handleEndCreditsClick() {
  finishEndCredits();
}

// ============================================================
// CHAPTER END SEQUENCE (post-leave-prison → level up)
// ============================================================

// Text blocks shown at each chapter-end stage. Mirrors the PY game's
// `chapter_end_stage` flow — stage 0 is the freedom narrative, stage 1
// is the rest + level-up dialog that flows into ABILITY_SELECT.
const CHAPTER_END_TEXTS = [
  [
    'You step through the door and into the light. The mountain air fills your lungs as you shield your eyes from the sun. Behind you, the dark corridors of the Kobold warren fade into memory.',
    'You are free. But the road to Qualibaf still lies ahead, and the mountains hold many more dangers...',
  ],
  [
    'You start climbing down the mountain path toward the river. After hours of walking, you find a sheltered clearing with a small stream. Apple trees and berry bushes grow wild here.',
    'You gather food, light a small fire, and lay down your weary body. The warmth of the flames and the sound of flowing water eventually lull you to sleep...',
  ],
];

function handleChapterEndClick(_x, _y) {
  // Click advances through the chapter-end stages. After the last stage,
  // hand off to the ability-select → perk-select → deck-tutorial → rest
  // inventory flow.
  chapterEndStage++;
  if (chapterEndStage >= CHAPTER_END_TEXTS.length) {
    // Kick off the level-up ability selection (tier 1 — matches the game
    // start). The existing handleAbilitySelectClick routes to PERK_SELECT
    // when level >= 2, and we hook the deck tutorial in at perk-pick time.
    abilityChoices = getOffsetAbilityChoices(selectedClass, 3);
    playSound('level_up_screen', 0.7);
    state = GameState.ABILITY_SELECT;
  }
}

function drawChapterEnd() {
  // Background: the "Leaving Prison" art gives the freedom-in-the-mountains
  // vibe. Fall back to deep indigo if the asset hasn't loaded.
  const bg = getEncounterBgImage('bg_leaving_prison');
  if (bg) {
    ctx.drawImage(bg, 0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  } else {
    ctx.fillStyle = '#0e0e14';
    ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);
  }
  // Darkening overlay so the dialog panel reads comfortably.
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  ctx.fillRect(0, 0, SCREEN_WIDTH, SCREEN_HEIGHT);

  const stage = Math.min(chapterEndStage, CHAPTER_END_TEXTS.length - 1);
  const texts = CHAPTER_END_TEXTS[stage];

  // Dialog panel centered on screen. Warm brown tone matches the outdoor
  // leaving-prison background (not the cold purple used for dungeon UI).
  const panelW = 960;
  const panelH = 520;
  const panelX = Math.round((SCREEN_WIDTH - panelW) / 2);
  const panelY = Math.round((SCREEN_HEIGHT - panelH) / 2);
  ctx.fillStyle = 'rgba(0,0,0,0.88)';
  ctx.fillRect(panelX, panelY, panelW, panelH);
  ctx.strokeStyle = Colors.GOLD;
  ctx.lineWidth = 2;
  ctx.strokeRect(panelX, panelY, panelW, panelH);

  ctx.textAlign = 'left';
  let cursorY = panelY + 60;
  const innerX = panelX + 40;
  const innerW = panelW - 80;
  const lineH = 30;
  const paragraphGap = 22;
  ctx.font = '21px Georgia, serif';
  ctx.fillStyle = Colors.WHITE;
  for (let i = 0; i < texts.length; i++) {
    const t = texts[i];
    // The dramatic "Level Up!" line gets the gold exclaim treatment.
    const isLevelUp = t === 'Level Up!';
    if (isLevelUp) {
      ctx.font = 'bold 32px Georgia, serif';
      ctx.fillStyle = Colors.GOLD;
      ctx.textAlign = 'center';
      cursorY += 12;
      ctx.fillText(t, panelX + panelW / 2, cursorY + 22);
      cursorY += 38;
      ctx.textAlign = 'left';
      ctx.font = '21px Georgia, serif';
      ctx.fillStyle = Colors.WHITE;
      continue;
    }
    const lines = wrapTextLong(t, innerW, 21);
    for (const line of lines) {
      ctx.fillText(line, innerX, cursorY);
      cursorY += lineH;
    }
    cursorY += paragraphGap;
  }

  // Prompt at the bottom.
  ctx.fillStyle = Colors.GRAY;
  ctx.font = '14px sans-serif';
  ctx.textAlign = 'center';
  const promptText = chapterEndStage + 1 < CHAPTER_END_TEXTS.length
    ? 'Click to continue...'
    : 'Click to choose a new ability...';
  ctx.fillText(promptText, panelX + panelW / 2, panelY + panelH - 24);
  ctx.textAlign = 'left';
}

// ============================================================
// DECK TUTORIAL (one-time, before first rest inventory)
// ============================================================

// Bottom-aligned "Continue" button rect — computed during draw so the
// click handler hits the exact pixels the player sees.
let _deckTutorialContinueRect = null;

function handleDeckTutorialClick(x, y) {
  if (_deckTutorialContinueRect && hitTest(x, y, _deckTutorialContinueRect)) {
    shownDeckTutorial = true;
    restMode = true;
    state = GameState.INVENTORY;
  }
}

